import { useState, useEffect } from "react";

export default function TripPlanner() {
  const [destinations, setDestinations] = useState([]);
  const [selected, setSelected] = useState(null);
  const [days, setDays] = useState([]);

  // Fetch destinations from backend
  useEffect(() => {
    fetch("http://localhost:5000/destinations")
      .then(res => res.json())
      .then(data => {
        console.log("Destinations:", data);
        setDestinations(data);
      })
      .catch(err => console.error(err));
  }, []);

  // Generate simple trip plan
  const generateTrip = (destination) => {
    const tripDays = [
      {
        day: "Day 1",
        activities: [
          "Arrival & Hotel Check-in",
          "Local exploration",
          "Dinner"
        ]
      },
      {
        day: "Day 2",
        activities: [
          "Sightseeing",
          "Popular attractions",
          "Local food"
        ]
      },
      {
        day: "Day 3",
        activities: [
          "Shopping",
          "Relaxation",
          "Return"
        ]
      }
    ];

    setSelected(destination);
    setDays(tripDays);
  };

  return (
    <div style={{ padding: 20 }}>
      <h1>Trip Planner 🌍</h1>

      {/* DESTINATION LIST */}
      {!selected && (
        <div>
          <h2>Select Destination</h2>

          {destinations.map((d) => (
            <div key={d._id} style={{
              border: "1px solid #ccc",
              padding: 10,
              margin: 10,
              borderRadius: 8
            }}>
              <h3>{d.name}</h3>
              <p>{d.description}</p>
              <p>₹{d.price}</p>

              <button onClick={() => generateTrip(d)}>
                Plan Trip →
              </button>
            </div>
          ))}
        </div>
      )}

      {/* TRIP PLAN */}
      {selected && (
        <div>
          <button onClick={() => setSelected(null)}>
            ← Back
          </button>

          <h2>{selected.name} Trip Plan</h2>

          {days.map((d, index) => (
            <div key={index} style={{
              border: "1px solid #ddd",
              padding: 15,
              margin: 10,
              borderRadius: 10
            }}>
              <h3>{d.day}</h3>

              <ul>
                {d.activities.map((a, i) => (
                  <li key={i}>{a}</li>
                ))}
              </ul>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}
